#include <stdio.h>
#include <stdlib.h>
#include <string.h>

typedef struct {
    int key;
    int cnt;
} Pair;

int cmp(const void *a, const void *b) {
    return ((Pair *)a)->key - ((Pair *)b)->key;
}

int main() {
    int T; if (scanf("%d", &T)!=1) return 0;
    while (T--) {
        int N; scanf("%d", &N);
        int *arr = (int*)malloc(N * sizeof(int));
        for (int i = 0; i < N; ++i) scanf("%d", &arr[i]);
        qsort(arr, N, sizeof(int), cmp);
        int singletons = 0;
        for (int i = 0; i < N; ) {
            int j = i;
            while (j < N && arr[j] == arr[i]) ++j;
            int freq = j - i;
            if (freq == 1) ++singletons;
            i = j;
        }
        int ans = (singletons + 1) / 2;
        printf("%d\n", ans);
        free(arr);
    }
    return 0;
}

